import{_ as e,o,c as t,ae as n}from"./chunks/framework.RRduUuAx.js";const m=JSON.parse('{"title":"This page will cover on how to benchmark on ps4","description":"","frontmatter":{},"headers":[],"relativePath":"miscellaneous/benchmark.md","filePath":"miscellaneous/benchmark.md","lastUpdated":null}'),i={name:"miscellaneous/benchmark.md"};function d(l,a,r,s,c,h){return o(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="this-page-will-cover-on-how-to-benchmark-on-ps4" tabindex="-1">This page will cover on how to benchmark on ps4 <a class="header-anchor" href="#this-page-will-cover-on-how-to-benchmark-on-ps4" aria-label="Permalink to &quot;This page will cover on how to benchmark on ps4&quot;">​</a></h1><ul><li><p>Benchmarking is the act of measuring performance and comparing the results to another system&#39;s results or a widely accepted standard through a unified procedure. This unified method of evaluating system performance can help answer questions such as:</p><ul><li>Is the system performing as it should?</li><li>What driver version should be used to get optimal performance?</li><li>Is the system capable of doing task x?</li></ul></li><li><p>Many tools can be used to determine system performance, the following provides a list of tools available.</p></li></ul><h2 id="basemark-gpu" tabindex="-1">Basemark GPU <a class="header-anchor" href="#basemark-gpu" aria-label="Permalink to &quot;Basemark GPU&quot;">​</a></h2><ul><li><p>Basemark GPU can be installed with following commands depending on your distro:</p><ul><li>Arch/Arch-based: <code>yay -S basemark --noconfirm</code></li><li>Fedora/Fedora-based: <code>flatpak install flathub com.basemark.BasemarkGPU</code></li><li>Debian/Debian-based: <code>flatpak install flathub com.basemark.BasemarkGPU</code></li></ul></li><li><p>For flatpaks you first need to install flatpak package and add the flatpak repo, installing the flatpak package will depend on your distro. To install the flatpak package for your distro check the commands below and pick the command acordingly:</p><ul><li>Fedora/Fedora-based: <code>sudo dnf install flatpak</code> then add the repo with <code>flatpak remote-add --if-not-exists flathub https://flathub.org/repo/flathub.flatpakrepo</code>.</li><li>Debian/Debian-based: <code>sudo apt install flatpak</code> then add the repo using the same command provided above.</li></ul></li><li><p>To run the benchmark type these commands acording to your distro:</p><ul><li>Arch/Arch-based: <code>basemark</code>.</li><li>For any distro running flatpak version use: <code>flatpak run com.basemark.BasemarkGPU</code>.</li></ul></li></ul><h2 id="mangohud" tabindex="-1">Mangohud <a class="header-anchor" href="#mangohud" aria-label="Permalink to &quot;Mangohud&quot;">​</a></h2><ul><li><p>MangoHud is a Vulkan and OpenGL overlay for monitoring system performance while inside applications and to record metrics for benchmarking.</p></li><li><p>You can install mangohud on your system by using the follow commands, pick a command acording to your distro:</p><ul><li>Arch/Arch-based: <code>sudo pacman -S mangohud lib32-mangohud --noconfirm</code>.</li><li>Debian/Debian-based: <code>sudo apt install mangohud mangohud:i386</code> if neccesery enable 32bit support by running <code>sudo dpkg --add-architecture i386</code></li><li>Fedora/Fedora-based: first you need to enable RPM Fusion, do that using this command <code>sudo dnf install \\ https://download1.rpmfusion.org/free/fedora/rpmfusion-free-release-$(rpm -E %fedora).noarch.rpm</code> then you can install by running <code>sudo dnf install mangohud mangohud.i686</code>.</li></ul></li><li><p>You can verify the installation by running <code>mangohud --version</code></p></li></ul><table tabindex="0"><thead><tr><th>Keyboard commands</th><th></th></tr></thead><tbody><tr><td>Keyboard Shortcut</td><td>Description</td></tr><tr><td>RShift+F12</td><td>Toggle overlay</td></tr><tr><td>RShift+F11</td><td>Change overlay position</td></tr><tr><td>RShift+F10</td><td>Toggle preset</td></tr><tr><td>LShift+F2</td><td>Toggle loading</td></tr><tr><td>LShift+F4</td><td>Reload config</td></tr></tbody></table><ul><li><p>Test the configuration by running these commands:</p><ul><li><code>mangohud glxgears</code></li><li><code>mangohud vkcube</code></li></ul></li></ul><h2 id="using-mangohud-with-steam" tabindex="-1">Using mangohud with steam <a class="header-anchor" href="#using-mangohud-with-steam" aria-label="Permalink to &quot;Using mangohud with steam&quot;">​</a></h2><ul><li><p>You can use mangohud for invidual game by putting <code>mangohud %command%</code> in the steam launch options</p></li><li><p>If you wish to use mangohud for all games you may start steam with mangohud, to do that run this command <code>mangohud steam</code></p></li><li><p>To use mangohud with vulkan games you need to use enviroment variables, you can use <code>MANGOHUD=1</code> to enable mangohud for vulkan games.</p></li></ul>',10)])])}const p=e(i,[["render",d]]);export{m as __pageData,p as default};
